module alu_32bit(A, B, opcode, invalid_result);
    input [31:0] A;
    input [31:0] B;
    input [2:0] opcode;
    output reg [31:0] invalid_result;

    always @(*) begin
        case (opcode)
            3'b000: invalid_result = A + B;   // Addition
            3'b001: invalid_result = A - B;   // Subtraction
            3'b010: invalid_result = A & B;   // AND
            3'b011: invalid_result = A | B;   // OR
            3'b100: invalid_result = A ^ B;   // XOR
            default: invalid_result = 32'b0;  // Default case
        endcase
    end
endmodule
